INSERT INTO public.photos VALUES (23461, 'Torreâ”œâ”‚n Fortea 1985', 'La Antigua Casa Fortea, con su torreâ”œâ”‚n gâ”œâ”‚tico-mudâ”œآ®jar del siglo XV, sita en la plaza de San Felipe de Zaragoza, es un palacio del siglo XVI que fue rehabilitado para albergar el â”œأ­rea de Cultura del Ayuntamiento de Zaragoza desde 1991. En 1985 presentaba este aspecto, sensiblemente distinto al actual. Fuente visual: Fotograma del audiovisual "El â”œâ•‘ltimo nombre. Miguel Labordeta" (Emilio Alfaro, 1985).', 1985, 1985, 1985, 'Anos 80', 'CENTRO', 41.65475900, -0.88206200, '0101000020E6100000556B6116DA39ECBF7EE19524CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20959878299.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20959878299.webp', 'https://www.flickr.com/photos/zaragozaantigua/20959878299/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23464, 'Plaza San Felipe 1967', 'Vista del torreâ”œâ”‚n de Fortea en la plaza de San Felipe. Fuente visual: Foto Leonardo Pâ”œآ®rez Obis, donada por â”œأ¼ngel Hernâ”œأ­ndez Mostajo para www.rafaelcastillejo.com', 1967, 1967, 1967, 'Anos 60', 'CENTRO', 41.65475900, -0.88206200, '0101000020E6100000556B6116DA39ECBF7EE19524CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23133296342.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23133296342.webp', 'https://www.flickr.com/photos/zaragozaantigua/23133296342/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23474, 'Plaza de San Felipe 1910', 'Placa autocroma de una vista de la plaza de San Felipe con el fondo escâ”œآ®nico de la antigua casa de los Cerdâ”œأ­n de Escatrâ”œâ”‚n, caracterâ”œآ،sticamente esquinera con la calle del Temple (a la izquierda) mediante su enorme torreâ”œâ”‚n. Fuente visual: Charles Jacquin photographe bibliotheques-specialisees.paris.fr/', 1910, 1910, 1910, 'Anos 10', 'CENTRO', 41.65477800, -0.88209400, '0101000020E61000002DEE3F321D3AECBFF511F8C3CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32133475674.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32133475674.webp', 'https://www.flickr.com/photos/zaragozaantigua/32133475674/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23480, 'Pl. de San Felipe 1985', 'Imagen capturada durante las obras de restauraciâ”œâ”‚n y reconversiâ”œâ”‚n de la antigua casa de los Cerdâ”œأ­n de Escatrâ”œâ”‚n (luego de los Fortea) al objeto de albergar las dependencias municipales del â”œأ¼rea de Cultura. La fotografâ”œآ،a se ha realizado desde la zona del patio interior. A la derecha, dando fachada principal a la inmediata plaza de San Felipe, traseras del Torreâ”œâ”‚n de Fortea y la Casa Montal. Al fondo, el moderno bloque edilicio del nâ”¬â•‘ 31 de la calle Torrenueva. Fuente visual: AMZ.', 1985, 1985, 1985, 'Anos 80', 'CENTRO', 41.65492800, -0.88180100, '0101000020E6100000259012BBB637ECBF0A9E42AED4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39106316095.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39106316095.webp', 'https://www.flickr.com/photos/zaragozaantigua/39106316095/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23487, 'Calle de la Torre Nueva 1951', 'Imagen del tramo de la calle de la Torre Nueva inmediatamente posterior a la plaza de San Felipe, centrado en el soleado tramo de los nâ”œâ•‘meros impares, donde destaca el edificio del Torreâ”œâ”‚n Fortea, el negocio de alimentaciâ”œâ”‚n regentado por Juliâ”œأ­n y Benigno Montal, y en primer tâ”œآ®rmino el dieciochesco cerramiento de ingreso al patio del inmueble del nâ”¬â•‘ 31 (accesorio a los nâ”œâ•‘meros 1-3 de la calle de Matâ”œآ،as Carrica, antigua de la Luna), que posiblemente fuera la antigua casa de Jerâ”œâ”‚nimo Urrea, y que en el momento de realizar la fotografâ”œآ،a era propiedad de los hijos de Pedro Laâ”œآ،n y regentado como negocio de venta de cueros.', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.65446100, -0.88172700, '0101000020E61000009301A08A1B37ECBFF4C0C760C5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/47954299601.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/47954299601.webp', 'https://www.flickr.com/photos/zaragozaantigua/47954299601/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23493, 'Plaza de San Felipe c.1908', 'Imagen capturada en la plaza de San Felipe y centrada en la imponente presencia de la antigua casa del siglo XV de los Cerdâ”œأ­n de Escatrâ”œâ”‚n y que desde el siglo XVIII es denominada de Fortea. A la izquierda, la calle del Temple y el inmueble esquinero del reputado comercio textil "Nâ”œâ•‘mero 1". A la derecha , vista parcial del inmueble del nâ”¬â•‘ 37 de la calle de Torrenueva, correspondiente al Almacâ”œآ®n de Frutos Coloniales Hijo de Navarro Pâ”œآ®rez, que aâ”œâ–’os despuâ”œآ®s continuarâ”œآ،a bajo la familia Montal.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.65486900, -0.88201700, '0101000020E6100000568330B77B39ECBF051555BFD2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51646815407.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51646815407.webp', 'https://www.flickr.com/photos/zaragozaantigua/51646815407/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23523, 'Calle Galo Ponte 2011', 'Foto: Oliver Duch. Vista, desde la esquina de las calles de Galo Ponte (izquierda) y Morata, del estado en agosto de 2011 de las obras de construcciâ”œâ”‚n de la nueva sede de la Audiencia Provincial de Zaragoza, inaugurada en 2012. Al fondo a la izquierda, el Coso Alto, con el palacio de los Condes de Morata o de los Luna, que quedarâ”œأ­ como Tribunal Superior de Justicia de Aragâ”œâ”‚n. Las plantas de este nuevo edificio se levantan coincidentes con las de su anexo precedente, el de la Imprenta Blasco, que asoma a la derecha, "por si en un futuro hay que unirlos". Fuente: Heraldo de Aragâ”œâ”‚n.', 2011, 2011, 2011, 'Siglo XXI', 'CENTRO', 41.65452200, -0.88269300, '0101000020E6100000620FED63053FECBF9A417C60C7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38242611492.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38242611492.webp', 'https://www.flickr.com/photos/zaragozaantigua/38242611492/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23662, 'Plaza de San Felipe 1937', 'Imagen de la plaza de San Felipe con detalle de la fachada de la antigua casa del marquâ”œآ®s de Villaverde. El "colegio de San Felipe", allâ”œآ، ubicado desde 1860, tras el golpe de estado de julio de 1936 se convirtiâ”œâ”‚ en otro de los espacios militarizados por los sublevados nacionalistas en Zaragoza, en un primer momento como sede del Sector nâ”¬â•‘ 1 de la organizaciâ”œâ”‚n paramilitar "Acciâ”œâ”‚n Ciudadana". La fotografâ”œآ،a ha sido realizada despuâ”œآ®s del decreto nâ”¬â•‘ 255 (promulgado en Salamanca en abril de ese aâ”œâ–’o), de unificaciâ”œâ”‚n de todas las fuerzas derechistas en un partido â”œâ•‘nico, siguiendo el modelo de los fascistas italianos y alemanes. Desde ese momento este colegio fue reconvertido como cuartel del "Primer Sector" de la milicia nacional de FET de las JONS, el nuevo partido surgido de la unificaciâ”œâ”‚n de Falange, requetâ”œآ®s, Acciâ”œâ”‚n Ciudadana, Renovaciâ”œâ”‚n Espaâ”œâ–’ola, Acciâ”œâ”‚n Popular, et altera. Aquâ”œآ، tambiâ”œآ®n la divisa era "todo por la patria", y la bandera monâ”œأ­rquica tapa el veterano cartel del colegio. Poco despuâ”œآ®s de tomar esta imagen, otro decreto estableciâ”œâ”‚ que todos los concejales y diputados provinciales tenâ”œآ،an que ser numerarios del partido. La replaceta junto a la antigua casona tenâ”œآ،a buena solanera para ponerse en posiciâ”œâ”‚n de espalda al sol.', 1937, 1937, 1937, 'Anos 30', 'CENTRO', 41.65477200, -0.88213600, '0101000020E6100000E8F9D346753AECBF132BA391CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25633742253.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25633742253.webp', 'https://www.flickr.com/photos/zaragozaantigua/25633742253/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23995, 'Zaragoza 1591', '"Entran en Zaragoza las tropas castellanas", dibujo del siglo XIX, româ”œأ­ntico y ahistâ”œâ”‚rico, recreando de esas formas la entrada del ejâ”œآ®rcito castellano en la ciudad durante las alteraciones del verano de 1591. Al fondo, la Torre Nueva, sorprendentemente precoz: estâ”œأ­ provista de su barroco juego de chapiteles. Fuente: www.artres.com/', 1591, 1591, 1591, 'Siglo XIX', 'CENTRO', 41.65475900, -0.88206200, '0101000020E6100000556B6116DA39ECBF7EE19524CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20714785970.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20714785970.webp', 'https://www.flickr.com/photos/zaragozaantigua/20714785970/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24010, 'Calle de Alfonso I 1986', 'Foto: Arturo Burgos. Comitiva fâ”œâ•‘nebre en el entierro del alcalde de Zaragoza Ramâ”œâ”‚n Sainz de Varanda, a su paso por la calle de Alfonso I, el 11 de enero de 1986 Fuente: Heraldo de Aragâ”œâ”‚n.', 1986, 1986, 1986, 'Anos 80', 'CENTRO', 41.65374600, -0.88154600, '0101000020E61000007F6DFDF49F35ECBF06F2ECF2ADD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23997397634.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23997397634.webp', 'https://www.flickr.com/photos/zaragozaantigua/23997397634/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24059, 'Calle de Alfonso I 1931', 'Celebraciones de la llegada de la Segunda Repâ”œâ•‘blica, el 14 de abril de 1931. En el centro, grupo de soldados que habâ”œآ،an formado parte de la columna del capitâ”œأ­n Galâ”œأ­n, en la sublevaciâ”œâ”‚n republicana de Jaca del 12 de diciembre de 1930. A la derecha, Joyerâ”œآ،a de Miguel Faci, en la esquina de la calle de Alfonso I con la plaza de Sas. Fuente visual: Heraldo de Aragâ”œâ”‚n.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65416100, -0.88102100, '0101000020E6100000DCDAC2F35231ECBFCAA8328CBBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31747330095.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31747330095.webp', 'https://www.flickr.com/photos/zaragozaantigua/31747330095/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24252, 'Calle de Alfonso I, c.1955', 'Luminosa imagen de la calle de Alfonso I donde destaca, a la derecha, el cartelâ”œâ”‚n publicitario del prestigioso Estudio Coyne en el inmueble del nâ”¬â•‘ 12, entresuelo. A la izquierda, el antiguo inmueble del nâ”¬â•‘ 17 esquinero con los nâ”œâ•‘meros 5, 7 y 9 de la calle de Fuenclara. Al fondo, el templo del Pilar.', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.65383500, -0.88134100, '0101000020E610000049F7730AF233ECBF76FD82DDB0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50129003428.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50129003428.webp', 'https://www.flickr.com/photos/zaragozaantigua/50129003428/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24476, 'La Bola Dorada 1910', 'Bazar La Bola Dorada de Joaquâ”œآ،n Grasa, en el nâ”œâ•‘mero 8 de la plaza de San Felipe, en su confluencia con la calle Montera (hoy Candalija 9). El fotâ”œâ”‚grafo era hijo del propietario y hermano del niâ”œâ–’o asomado al balcâ”œâ”‚n, Emilio, que se harâ”œآ،a cargo aâ”œâ–’os despuâ”œآ®s del negocio. Fuente: "Aurelio Grasa 1893-1972", Galerâ”œآ،a Costa, 3, 1976. Pâ”œأ­gina 10. Formâ”œâ”‚ parte de la exposiciâ”œâ”‚n conmemorativa celebrada en dicha galerâ”œآ،a en 1978. www.aureliograsa.es', 1910, 1910, 1910, 'Anos 10', 'CENTRO', 41.65454000, -0.88191100, '0101000020E6100000EB71DF6A9D38ECBF40F67AF7C7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21223699900.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21223699900.webp', 'https://www.flickr.com/photos/zaragozaantigua/21223699900/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24521, 'Chocolate Francisco Navarro 1890', 'Imagen publicitaria de 1890 de la "fâ”œأ­brica de chocolate elaborado a brazo" de Francisco Navarro, con direcciâ”œâ”‚n en la calle Torre Nueva 37. Representa la Torre Nueva antes de ser desmochada, con la casa de la familia Cerdâ”œأ­n de Escatrâ”œâ”‚n (Torreâ”œâ”‚n Fortea) a su izquierda. Fuente: Oficina Espaâ”œâ–’ola de Patentes y Marcas.', 1890, 1890, 1890, 'Siglo XIX', 'CENTRO', 41.65472200, -0.88213500, '0101000020E6100000D105F52D733AECBF61FC34EECDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39292070314.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39292070314.webp', 'https://www.flickr.com/photos/zaragozaantigua/39292070314/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25146, 'Torre Nueva 1813', 'Imagen de la Torre Nueva dibujada por Edward Hanke Locker en 1813, convertida en la "Torre de San Felipe" en la ediciâ”œâ”‚n de 1824 de "Views in Spain", por John Murray. Si interpretamos bien la ilustraciâ”œâ”‚n, la torre de la iglesia de San Felipe que aparece representada serâ”œآ،a el desproporcionado torreâ”œâ”‚n de la izquierda, mientras que la Torre Nueva serâ”œآ،a, empequeâ”œâ–’ecida respecto a su real tamaâ”œâ–’o, la de la derecha. Al fondo, el palacio de los marqueses de Villaverde. Por la plaza de San Felipe circula una procesionaria. Fuente visual: www.ebay.es/', 1813, 1813, 1813, 'Siglo XIX', 'CENTRO', 41.65477200, -0.88213600, '0101000020E6100000E8F9D346753AECBF132BA391CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26502678592.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26502678592.webp', 'https://www.flickr.com/photos/zaragozaantigua/26502678592/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25183, 'Torre Nueva 1865', 'Curioso dibujo de la Torre Nueva en la plaza de San Felipe que parece intentar reflejar un hâ”œآ،brido entre el estado original de la torre al que se le suma el caracterâ”œآ،stico remate barroco en chapitel, que aquâ”œآ، aparece achatado de forma extraâ”œâ–’a. Al fondo y a la izquierda, en trazo mâ”œأ­s tenue, la casa de los condes de Argillo y marqueses de Villaverde, y el muro de cerramiento de la iglesia de San Felipe.', 1865, 1865, 1865, 'Siglo XIX', 'CENTRO', 41.65476500, -0.88210300, '0101000020E6100000F9821612303AECBF60C8EA56CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50902804946.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50902804946.webp', 'https://www.flickr.com/photos/zaragozaantigua/50902804946/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25667, 'Mâ”œآ®ndez Nâ”œâ•‘â”œâ–’ez 1966', 'Imagen de la calle Mâ”œآ®ndez Nâ”œâ•‘â”œâ–’ez a la altura, a la derecha, de la antigua plazuela de la Cabra, interesante espacio urbano con restos de casonas de notable prestigio urbano. A la izquierda, aspecto de la calle cuando en los bajos del nâ”¬â•‘ 16 (a los que se aâ”œâ–’adâ”œآ،a el 18 de la vecina calle Libertad) estaba radicado el establecimiento comercial de la veterana empresa "Muebles y Camas Metâ”œأ­licas Viuda de S. Irisarri", cuya fâ”œأ­brica estaba en el Barrio del Castillo. Al fondo, Mâ”œآ®ndez Nâ”œâ•‘â”œâ–’ez asciende desde su arranque en Alfonso I. Fuente: Gerardo Sancho Ramo (Archivo Pâ”œâ•‘blico Municipal).', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.65378100, -0.87976300, '0101000020E61000001B6327BC0427ECBF83DF8618AFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24049716615.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24049716615.webp', 'https://www.flickr.com/photos/zaragozaantigua/24049716615/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25872, 'La Torre Nueva 1835', 'Grabado de la Torre Nueva realizado por Charles Heath en Londores (1835), basado fielmente en el canâ”œâ”‚nico dibujo previo de Edward Hanke Locker en 1813. Fuente visual: Fondo Documental Histâ”œâ”‚rico de las Cortes de Aragâ”œâ”‚n', 1835, 1835, 1835, 'Siglo XIX', 'CENTRO', 41.65474400, -0.88209200, '0101000020E6100000FF058200193AECBF49A0C1A6CED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14688169238.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14688169238.webp', 'https://www.flickr.com/photos/zaragozaantigua/14688169238/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
