INSERT INTO public.photos VALUES (25874, 'Der Haengende Thurm 1837', 'Der Haengende Thurm in Saragossa. Johann Gabriel Friedrich Poppel, (ca. 1850). Reproducciâ”œâ”‚n del grabado de E. Finden segâ”œâ•‘n un dibujo de J. F. Lewis de 1837. Fuente: Aragâ”œâ”‚n en el mundo. CAI, 1988.', 1837, 1837, 1837, 'Siglo XIX', 'CENTRO', 41.65474600, -0.88208600, '0101000020E6100000774D486B0C3AECBFEA9788B7CED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14877300682.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14877300682.webp', 'https://www.flickr.com/photos/zaragozaantigua/14877300682/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25876, 'Torre Nueva 1844', '"Torre inclinada (Zaragoza)". A la derecha, el Palacio de los Cerdâ”œأ­n de Escatrâ”œâ”‚n. Al fondo, el Palacio de Argillo; a la izquierda, la iglesia de San Felipe. Fuente visual: "Recuerdos y Bellezas de Espaâ”œâ–’a. Obra destinada a dar a conocer sus monumentos, antigâ”œâ•‌edades y vistas pintorescas en lâ”œأ­minas dibujadas del natural y litografiadas por F. J. Parcerisa, acompaâ”œâ–’adas de texto por P. Piferrer y J. M. Quadrado. Aragâ”œâ”‚n: Josâ”œآ® Marâ”œآ،a Quadrado. 1844."', 1844, 1844, 1844, 'Siglo XIX', 'CENTRO', 41.65475900, -0.88206200, '0101000020E6100000556B6116DA39ECBF7EE19524CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19477637546.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19477637546.webp', 'https://www.flickr.com/photos/zaragozaantigua/19477637546/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25877, 'Plaza San Felipe 1980', 'Plaza de San Felipe, con trâ”œأ­fico en la calle Torre Nueva. Al fondo, palacio de Argillo. Fuente: Zaragoza en imâ”œأ­genes, CAZAR, 1980.', 1980, 1980, 1980, 'Anos 80', 'CENTRO', 41.65475900, -0.88206200, '0101000020E6100000556B6116DA39ECBF7EE19524CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19638347474.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19638347474.webp', 'https://www.flickr.com/photos/zaragozaantigua/19638347474/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25880, 'Torre Nueva c.1863', 'Primera de las imâ”œأ­genes en altura desde la calle Torre Nueva, capturadas por Laurent y Câ”œآ،a, retratando la Torre Nueva en la plaza de San Felipe. Fuente visual: Jean Laurent y Câ”œآ،a, Archivo Ruiz Vernacci (Fototeca del Patrimonio Histâ”œâ”‚rico, www.mcu.es/)', 1863, 1863, 1863, 'Siglo XIX', 'CENTRO', 41.65475900, -0.88206200, '0101000020E6100000556B6116DA39ECBF7EE19524CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22412575193.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22412575193.webp', 'https://www.flickr.com/photos/zaragozaantigua/22412575193/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25881, '&quot;Torre Nueva&quot; 1976', 'Imagen de la Torre Nueva en la epifanâ”œآ،a discogrâ”œأ­fica del grupo musical "La Bullonera". La atinada composiciâ”œâ”‚n visual aprovecha una fotografâ”œآ،a de J. Laurent de este icono de la Zaragoza demolida por sus propios, para confrontar dos antagâ”œâ”‚nicas ciudades: la de la derecha, azulona, selecta, emprendedora, a color; la de la izquierda, roja, basal, colectiva, en tonos grises, que pugna por sostener la torre, porque es de todos. Esta realidad bipolar, reconocible e identitaria, luego confluyâ”œâ”‚ en amable mezcolanza de churros y merinos, dando como resultado el ahora en el que estamos. Fuente visual: disco en vinilo "La Bullonera" (Javier Maestre, Eduardo Paz), Madrid, Movieplay, 1976. Ilustraciâ”œâ”‚n y diseâ”œâ–’o de la carpeta por Josâ”œآ® Luis Lasala, en colaboraciâ”œâ”‚n con Natalio Bayo.', 1976, 1976, 1976, 'Anos 70', 'CENTRO', 41.65475900, -0.88206200, '0101000020E6100000556B6116DA39ECBF7EE19524CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23043877271.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23043877271.webp', 'https://www.flickr.com/photos/zaragozaantigua/23043877271/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25882, 'Calle Torre Nueva 1971', 'Calle Torre Nueva. Al fondo, plaza de San Felipe. Mâ”œأ­s allâ”œأ­, la calle continâ”œâ•‘a hasta el Mercado Central. Fuente visual: Foto Leonardo Pâ”œآ®rez Obis, donada por â”œأ¼ngel Hernâ”œأ­ndez Mostajo para www.rafaelcastillejo.com', 1971, 1971, 1971, 'Anos 70', 'CENTRO', 41.65470000, -0.88162100, '0101000020E610000028F04E3E3D36ECBF7958A835CDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23133619532.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23133619532.webp', 'https://www.flickr.com/photos/zaragozaantigua/23133619532/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25883, 'Plaza de San Felipe c.1972', 'Tramo de la calle de la Torre Nueva que atraviesa la plaza de San Felipe. A la derecha, establecimientos comerciales de bebidas espirituosas y de gâ”œآ®neros de punto en los bajos del Torreâ”œâ”‚n y casa-palacio Fortea, antigua vivienda de los Cerdâ”œأ­n de Escatrâ”œâ”‚n. En la dâ”œآ®cada siguiente, este conjunto serâ”œأ­ adquirido y restaurado por el Ayuntamiento, y luego adaptado a usos municipales, desahogando parcialmente el entorno de vehâ”œآ،culos a motor aparcados.', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.65475900, -0.88206200, '0101000020E6100000556B6116DA39ECBF7EE19524CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23177708125.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23177708125.webp', 'https://www.flickr.com/photos/zaragozaantigua/23177708125/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25884, 'Plaza de San Felipe 1968', 'Imagen del decorativo pozo en peculiar estilo neo-româ”œأ­nico ubicado en la plaza de San Felipe, muy cerca de donde estuviera la Torre Nueva. Al fondo, a la izquierda, la plazuela de ingreso al colegio de San Felipe. A la derecha, plazuela de engarce con las calles Torre Nueva, y Temple. Posteriores intervenciones en la plaza derivaron al pozo en situaciâ”œâ”‚n de paradero desconocido. Fuente visual: Walter Schrâ”œأ‚der (www.bildindex.de/)', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.65475900, -0.88206200, '0101000020E6100000556B6116DA39ECBF7EE19524CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23205559710.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23205559710.webp', 'https://www.flickr.com/photos/zaragozaantigua/23205559710/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25886, 'Torre Nueva c.1843', '"The leaning tower of Zaragoza". Este grabado fue publicado en el "Illustrated home book of the world''s great nations. Being a geographical, historical and pictorial encyclopedia", en Chicago, 1893. Estaba incluido en el capâ”œآ،tulo dedicado al "romantic land of Spain", un folclâ”œâ”‚rico recorrido por todos los tâ”œâ”‚picos imaginables a este lado de los Pirineos, con el valor aâ”œâ–’adido de una distorsionada mirada desde el pujante norte del otro lado del Atlâ”œأ­ntico. Se trataba, ademâ”œأ­s, de la â”œâ•‘nica ilustraciâ”œâ”‚n de Zaragoza incluida en esa obra cuando, casualmente, desde un aâ”œâ–’o antes de su ediciâ”œâ”‚n esta inmortal ciudad ya no contaba, por derribo promovido, con la Torre Nueva. El tardobarroco triple chapitel que la remataba, ya no estaba desde 1878. El grabado, cuyo "eminente artista" autor no es nominado, sigue bebiendo del canâ”œâ”‚nico dibujo de la Torre Nueva realizado por Edward Hanke Locker en 1813, con algunas modificaciones. Posiblemente, el tumulto que se desarrolla en la plaza de San Felipe estuviera relacionado con la resistencia a los pronunciamientos militares (asâ”œآ، se llamaban a los golpes de estado durante el siglo XIX) de 1843, durante la regencia del general Espartero. A la izquierda, la torre de la iglesia de San Felipe; al fondo, la galerâ”œآ،a de arquillos del palacio de los marqueses de Villaverde; en el centro de la acciâ”œâ”‚n, la "Torre inclinada de Zaragoza".', 1843, 1843, 1843, 'Siglo XIX', 'CENTRO', 41.65477200, -0.88213600, '0101000020E6100000E8F9D346753AECBF132BA391CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26570720156.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26570720156.webp', 'https://www.flickr.com/photos/zaragozaantigua/26570720156/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25887, 'Torre Nueva 1864', 'Vista de la Torre Nueva. Fuente: Mariano Jâ”œâ•‘dez y Ortiz. Colecciâ”œâ”‚n Boisset-Ibâ”œأ­â”œâ–’ez. Libro Primeros tiempos de la fotografâ”œآ،a en Zaragoza.', 1864, 1864, 1864, 'Siglo XIX', 'CENTRO', 41.65477200, -0.88213600, '0101000020E6100000E8F9D346753AECBF132BA391CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28490644371.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28490644371.webp', 'https://www.flickr.com/photos/zaragozaantigua/28490644371/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25888, 'Pl. de San Felipe 1968', 'Imagen del patio al aire (y sol) de la antigua casa del infanzâ”œâ”‚n Francisco Sanz de Cortâ”œآ®s, luego marquâ”œآ®s de Villaverde, sita en la plaza de San Felipe, inmediata a la iglesia parroquial. En el siglo XIX pasâ”œâ”‚ a manos de la condesa de Argillo, y acogiâ”œâ”‚ al Colegio de San Felipe. En el siglo XX fue una de las sedes de la paramilitar Acciâ”œâ”‚n Ciudadana, y luego lo fue de la ONCE. Desde 1977 es propiedad municipal, como museo. Fuente visual: Walter Schrâ”œأ‚der, en www.bildindex.de/', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.65475900, -0.88245600, '0101000020E61000005516855D143DECBF7EE19524CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32370057505.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32370057505.webp', 'https://www.flickr.com/photos/zaragozaantigua/32370057505/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25889, 'Plaza de San Felipe 1977', 'Imagen parcial de la renovada plaza de San Felipe, tras una de las operaciones entonces denominadas "de embellecimiento" de espacios de la vieja ciudad, que incluyâ”œâ”‚ esta estâ”œآ®tica valla ornamental sin utilidad prâ”œأ­ctica conocida, tal vez como recuerdo de la "valla mental" que suponâ”œآ،a la antigua Torre Nueva (ubicada en ese mismo lugar) para los vecinos que exigieron su aplaudida demoliciâ”œâ”‚n. Parece ser que el concepto "plaza dura" ya se estaba imponiendo como prâ”œأ­ctica habitual en el tratamiento de los espacios comunitarios de nueva ola. Al fondo de la imagen, almacenes de tejidos instalados en los bajos comerciales de la antigua casa de los Cerdâ”œأ­n de Escatrâ”œâ”‚n. Fuente visual: foto Gerardo Sancho Ramo, en AMZ.', 1977, 1977, 1977, 'Anos 70', 'CENTRO', 41.65477800, -0.88209400, '0101000020E61000002DEE3F321D3AECBFF511F8C3CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33244671871.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33244671871.webp', 'https://www.flickr.com/photos/zaragozaantigua/33244671871/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25890, 'Calle de Gil Berges 1972', 'Imagen centrada en el nâ”¬â•‘ 1 (antiguo nâ”¬â•‘ 5) de la calle de Gil Berges, en cuyos bajos estaba radicado el local de la veterana churrerâ”œآ،a "Bola de Plata", en un antiguo edificio posiblemente del siglo XVI que fue finalmente derribado a finales de los aâ”œâ–’os noventa de la pasada centuria. A la izquierda, fuera de plano, la calle de Agustines. Hacia la derecha se accede a la iglesia parroquial de San Felipe, y a la plaza homâ”œâ”‚nima. Este era considerado un "rincâ”œâ”‚n tâ”œآ،pico" zaragozano, pintoresco, costumbrista, y contingente, que ya entonces se auguraba sentenciado a desaparecer por el impacto de una modernidad que parece ser que no hallaba otra forma de encontrar acomodo en zonas como esta, que no fuera con la piqueta por delante. Tambiâ”œآ®n parece que era necesario, pese a lo recoleto de la zona, recordar a los conductores que el estacionamiento no estaba recomendado. Fuente visual: fotografâ”œآ،a de Luis Mompel, en Heraldo de Aragâ”œâ”‚n.', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.65427800, -0.88256300, '0101000020E6100000D61BB5C2F43DECBF033FAA61BFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34366060633.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34366060633.webp', 'https://www.flickr.com/photos/zaragozaantigua/34366060633/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25891, 'Calle Torre Nueva c.1969', 'Imagen capturada en la calle de Torre Nueva y centrada en la esquinera fachada del nâ”¬â•‘ 29, correspondiente con el veterano negocio de alimentaciâ”œâ”‚n allâ”œآ، ubicado desde 1890 que desde 1919 es reconocido como Casa Montal. Hacia la izquierda, fuera de plano, la antigua casa de los Cerdâ”œأ­n de Escatrâ”œâ”‚n (luego de los Fortea). Fuente visual: www.montal.es', 1969, 1969, 1969, 'Anos 60', 'CENTRO', 41.65478300, -0.88171600, '0101000020E610000099840B790437ECBF077DE9EDCFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39978706102.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39978706102.webp', 'https://www.flickr.com/photos/zaragozaantigua/39978706102/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25892, 'Ejecuciâ”œâ”‚n nobles 1591', '"Ejecuciâ”œâ”‚n de los nobles don Diego de Heredia y don Juan de Luna en Zaragoza". Ilustraciâ”œâ”‚n de F. Blanch que recrea el paseâ”œآ،llo previo a la ejecuciâ”œâ”‚n de los nobles citados, que junto a Pedro Fuertes, Francisco de Ayerbe y otros fueron condenados a muerte por participar en las alteraciones de Zaragoza de 1591. Tras ellos fue ejecutado tambiâ”œآ®n el Justicia Juan de Lanuza. La comitiva viene de la Torre Nueva y se dirige a la picota de la plaza del Mercado. Fuente visual: Historia de Espaâ”œâ–’a, Miguel Seguâ”œآ،, 1910, en todocoleccion.net.', 1591, 1591, 1591, 'Siglo XIX', 'CENTRO', 41.65511500, -0.88256400, '0101000020E6100000ED0F94DBF63DECBF3D0FEECEDAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40390073704.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40390073704.webp', 'https://www.flickr.com/photos/zaragozaantigua/40390073704/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25893, 'Calle de Fuenclara c.1973', 'Imagen centrada en la fachada de la renacentista y enorme casa de los condes de Fuenclara, sita en la homâ”œâ”‚nima calle y esquinera con las calles del Desengaâ”œâ–’o y de Torresecas. Ademâ”œأ­s de los seis locales comerciales ubicados en sus bajos, en â”œآ®l se exhibâ”œآ،an pelâ”œآ،culas en la sala del cine Arlequâ”œآ،n. Al fondo, el inmueble esquinero entre las calles de Agustines y de Gil Berges. Fuente visual: AMZ.', 1973, 1973, 1973, 'Anos 70', 'CENTRO', 41.65401400, -0.88212300, '0101000020E6100000C09481035A3AECBF259012BBB6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41036439775.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41036439775.webp', 'https://www.flickr.com/photos/zaragozaantigua/41036439775/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25894, 'Calle del Temple 1974', 'Imagen centrada en el destacable ingreso al antiguo nâ”¬â•‘ 15 de la calle del Temple, inmueble esquinero con la calle del Olmo. Aâ”œâ–’os mâ”œأ­s tarde, tanto este como el inmediato nâ”¬â•‘ 13, ademâ”œأ­s del nâ”¬â•‘ 11, que ya era solar, fueron habilitados como un provisional espacio de encuentro, convivencia y solaz ciudadano en el que este antiguo portal de ingreso fue el â”œâ•‘nico resto edilicio que se mantuvo en pie. A principios del siglo XXI sobre este solar se emprendiâ”œâ”‚ un desarrollo constructivo que conformâ”œâ”‚ el actual gran inmueble del nâ”¬â•‘ 18 de la calle del Olmo. Esta vieja portada fue entonces derribada. Fuente visual: AMZ.', 1974, 1974, 1974, 'Anos 70', 'CENTRO', 41.65551300, -0.88201600, '0101000020E61000003F8F519E7939ECBF2A8D98D9E7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/42267438434.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/42267438434.webp', 'https://www.flickr.com/photos/zaragozaantigua/42267438434/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26025, 'Tejados 1899', 'A finales de la diecinueve centuria de la Era, desde las alturas del antiguo palacio de Guara, en la calle de la Montera, un vistazo en direcciâ”œâ”‚n norte choca con el frontal, al fondo, de la basâ”œآ،lica del Pilar recayente a la plaza del mismo nombre. Justo enfrente, emerge solitaria la reciente torre de Santiago, acabada unos pocos aâ”œâ–’os antes, y la imagen se corta a la derecha justo donde comienza el secular arranque que unos pocos aâ”œâ–’os despuâ”œآ®s, terminado ya en forma de torre, serâ”œأ­ denominada "Nuestra Seâ”œâ–’ora del Pilar" para redundar el culto mariano en sâ”œآ، mismo. En medio, el caracterâ”œآ،stico mundo de los tejados, solanares y remates edilicios frontero entre el antiguo barrio de San Felipe, y el del Pilar. Fuente visual: Francisco Gâ”œâ”‚rriz, Archivo Municipal de Zaragoza', 1899, 1899, 1899, 'Siglo XIX', 'CENTRO', 41.65440400, -0.88154500, '0101000020E610000068791EDC9D35ECBF902FA182C3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28722003590.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28722003590.webp', 'https://www.flickr.com/photos/zaragozaantigua/28722003590/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21272, 'Clâ”œآ،nica Dr. Lozano 1905', 'Imagen de la original fâ”œأ­brica de la particular clâ”œآ،nica-palacete del mâ”œآ®dico y cirujano Ricardo Lozano Monzâ”œâ”‚n, estratâ”œآ®gicamente situada entre el paseo de Sagasta y la calle Lagasca, con diseâ”œâ–’o de Fâ”œآ®lix Navarro. En 1916 serâ”œأ­ ampliada y bastante modificada, a cargo de Manuel del Busto. Esto era lo que se veâ”œآ،a antes de, desde la esquina con Lagasca. Fuente visual: "Zaragoza. Arquitectura siglo XX" (Jesâ”œâ•‘s Martâ”œآ،nez Verâ”œâ”‚n).', 1905, 1905, 1905, 'Anos 1900', 'CENTRO', 41.64496900, -0.88607300, '0101000020E6100000A3CB9BC3B55AECBF88F71C588ED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22508018031.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22508018031.webp', 'https://www.flickr.com/photos/zaragozaantigua/22508018031/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21351, 'Paseo de Sagasta 1905', 'Imagen capturada en el arranque del paseo de Sagasta, donde a la izquierda queda el tramo comprendido entre el Velâ”œâ”‚dromo y la calle de Mariano Lagasca, y a la derecha el tramo recayente al colegio del Sagrado Corazâ”œâ”‚n o de "las francesas". Por el centro del bulevar transita su recorrido en ascenso hasta la playa de Torrero el elâ”œآ®ctrico coche nâ”œâ•‘mero 17 de la serie "Primitivos" en servicio en la tranviaria lâ”œآ،nea de Torrero.', 1905, 1905, 1905, 'Anos 1900', 'CENTRO', 41.64524900, -0.88581500, '0101000020E6100000B8CCE9B29858ECBF6B63EC8497D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54218344204.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54218344204.webp', 'https://www.flickr.com/photos/zaragozaantigua/54218344204/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24978, 'Josâ”œآ® Luis Violeta 1978', 'El futbolista Josâ”œآ® Luis Violeta (Zaragoza, 1941) alza un trofeo con la reproducciâ”œâ”‚n de la estatua del Augusto de Prima Porta, durante su homenaje en el campo de fâ”œâ•‘tbol de La Romareda, el 21 de mayo de 1978. "El Leâ”œâ”‚n de Torrero" habâ”œآ،a jugado en el Real Zaragoza durante 14 temporadas (1963-1977). Fuente visual: www.resultados-futbol.com/foto/jose-luis-violeta_711077', 1978, 1978, 1978, 'Anos 70', 'UNIVERSIDAD', 41.63637700, -0.90173500, '0101000020E6100000EC12D55B03DBECBF9B7631CD74D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21961617041.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21961617041.webp', 'https://www.flickr.com/photos/zaragozaantigua/21961617041/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21384, 'P.â”¬â•‘ de Sagasta 1915', '"Calle. Hombre" (sic). Imagen del arranque del Paseo de Sagasta. El seâ”œâ–’or con canotier estâ”œأ­ bajando por la larga acera del Colegio del Sagrado Corazâ”œâ”‚n, a punto de llegar a la glorieta del monumento al reducto del Pilar. Al otro lado del arbolado paseo, algunos de los edificios de los pares, con sus peculiares y exclusivos retranqueos cerrados con verjas (algunos, ajardinados). En la acera de los nâ”œâ•‘meros impares, los edificios se aferraron a la linealidad del muro del colegio, y se negaron a retranquearse, ganando un espacio extra "gratis et amore", como sâ”œâ”‚lo era posible cuando las familias de la alta sociedad eran, a la vez, quienes hacâ”œآ،an y deshacâ”œآ،an las cosas del Ayuntamiento. Los curiosos entrantes y salientes del desigual lado oriental del paseo se podrâ”œآ،an explicar en funciâ”œâ”‚n del apellido del propietario-concejal afectado. Cosas del sistema polâ”œآ،tico de la Restauraciâ”œâ”‚n Borbâ”œâ”‚nica. Buena maâ”œâ–’ana para pasear, si seâ”œâ–’or. Por el paseo baja un pequeâ”œâ–’o cauce residual por gravedad. Los raâ”œآ،les del tranvâ”œآ،a de Torrero van por el centro del paseo, para no molestar a los 200 vehâ”œآ،culos a motor de explosiâ”œâ”‚n matriculados en la ciudad, y provocar asâ”œآ، un caos civilizatorio. Fuente visual: AHPZ-Archivo Coyne.', 1915, 1915, 1915, 'Anos 10', 'CENTRO', 41.64582700, -0.88585800, '0101000020E61000008ACC5CE0F258ECBFD8EF8975AAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16885321574.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16885321574.webp', 'https://www.flickr.com/photos/zaragozaantigua/16885321574/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23784, 'Alfocea 1999', 'El barrio rural de Alfocea, en una vista con los montes del Castellar al fondo. Protagoniza la imagen la barroca iglesia parroquial de la Inmaculada Concepciâ”œâ”‚n, construida en 1683 y adosada a un anterior templo româ”œأ­nico que fue demolido en 1974. Este barrio zaragozano, que fue pueblo independiente hasta 1887, tiene como â”œâ•‘nico acceso un puente construido sobre el râ”œآ،o Ebro en 1968, proyectado por el ingeniero oscense Juan Josâ”œآ® Arenas, que lo comunica con Monzalbarba.', 1999, 1999, 1999, 'Anos 90', NULL, 41.72409100, -0.95090700, '0101000020E6100000F8325184D46DEEBFFA298E03AFDC4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50199320841.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50199320841.webp', 'https://www.flickr.com/photos/zaragozaantigua/50199320841/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21400, 'P.â”¬â•‘ de Sagasta c.1912', 'Imagen del arranque del paseo de Sagasta encaminado en direcciâ”œâ”‚n sur, tras el cruce del puente de Santa Engracia. A la derecha, el velâ”œâ”‚dromo de los Elâ”œآ،seos y las primeras viviendas de este ascendente ensanche burguâ”œآ®s. A la izquierda, el pequeâ”œâ–’o obelisco instalado en 1909 en la Glorieta de Pâ”œآ®rez Galdâ”œâ”‚s (luego, Sasera) en recuerdo a los irreductibles del reducto del Pilar, con la necrofâ”œآ،lica inscripciâ”œâ”‚n "Morir por la Virgen del Pilar o vencer". Tras la foresta, el colegio del Salvador de los PP. Jesuitas, y el de las religiosas del Sagrado Corazâ”œâ”‚n de Jesâ”œâ•‘s, o "francesas". Entre ambos, el paseo de las Damas. A pesar de tratarse de un ensanche burguâ”œآ®s, este paseo carecerâ”œآ،a de alcantarillado hasta unos aâ”œâ–’os despuâ”œآ®s, cuando se aprobara y realizara el proyecto de Yarza, y el firme no estaba pavimentado. Por el centro del paseo, todavâ”œآ،a el tendido viario de la electrificada lâ”œآ،nea de Torrero.', 1912, 1912, 1912, 'Anos 10', 'CENTRO', 41.64588300, -0.88557900, '0101000020E6100000C1C760C5A956ECBF6C054D4BACD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22937594986.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22937594986.webp', 'https://www.flickr.com/photos/zaragozaantigua/22937594986/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21521, 'P.â”¬â•‘ de Sagasta 1923', '"Entierro Valenzuela", Julio Requejo, 1923. Entierro de Rafael de Valenzuela y Urzaiz, militar muerto durante la africana guerra colonial del Rif (Protectorado Espaâ”œâ–’ol de Marruecos). En la imagen, perspectiva del fâ”œآ®retro a la espera del inicio del ceremonial recorrido en el principio del Paseo de Sagasta. En este caso, el objetivo ha tomado como fondo el edificio del Colegio del Salvador, a la derecha, y un paseo muy tranquilo, con niâ”œâ–’os jugando. A la izquierda, lejana imagen de los edificios de la plaza de Aragâ”œâ”‚n. Fuente: AHPZ.', 1923, 1923, 1923, 'Anos 20', 'CENTRO', 41.64582700, -0.88585800, '0101000020E61000008ACC5CE0F258ECBFD8EF8975AAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16522049729.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16522049729.webp', 'https://www.flickr.com/photos/zaragozaantigua/16522049729/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21626, 'Cubrimiento Huerva 1926', 'Imagen capturada a nivel del râ”œآ،o Huerva durante las obras de la primera fase de su cubrimiento en el tramo urbano desde la plaza de Paraâ”œآ،so hasta la curva de la Veneciana (unos 450 metros de largo). Era una de las actuaciones para el desarrollo del acceso al ensanche de Miralbueno y el Parque de Zaragoza o de Buenavista. El cauce fluvial ya ha sido modificado para recibir el cubrimiento mediante la construcciâ”œâ”‚n de dos muros de contenciâ”œâ”‚n de hormigâ”œâ”‚n en masa de unos ocho metros de altura en los que se han insertado unas mâ”œآ®nsulas donde apoyar las vigas de hormigâ”œâ”‚n armado de catorce metros de luz. Al fondo se siluetea el antiguo puente de Santa Engracia bajo la plaza del Paraâ”œآ،so. En superficie, el nuevo vial resultante serâ”œأ­ denominado en un primer momento Gran Vâ”œآ،a. Consecuencia inmediata de ello fue la conversiâ”œâ”‚n de la plaza de Paraâ”œآ،so en el punto de encuentro de hasta cinco grandes vâ”œآ،as de trâ”œأ­nsito (los paseos de Independencia, Pamplona y Sagasta, y los dos nuevos viales resultado del cubrimiento), lo que a corto plazo derivâ”œâ”‚ en su conversiâ”œâ”‚n en una mera rotonda de trâ”œأ­fico rodado con graves problemas de movilidad que perduran en el tiempo. Cierta lectura mâ”œأ­s profunda de la gâ”œآ®nesis y desarrollo del cubrimiento del Huerva vincularâ”œآ،a el proyecto a los ritmos de los intereses especulativos del sector propietario e inmobiliario que buscaban aumentar las expectativas urbanâ”œآ،sticas de los terrenos comprendidos entre la plaza de Paraâ”œآ،so y el parque de Buenavista, hasta entonces convenientemente mantenidos en situaciâ”œâ”‚n de barbecho. Fuente visual: â”œأ¼ngel Aâ”œآ،sa y Hermano.', 1926, 1926, 1926, 'Anos 20', 'CENTRO', 41.64598300, -0.88860200, '0101000020E61000004B2025766D6FECBFD0622992AFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35950343474.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35950343474.webp', 'https://www.flickr.com/photos/zaragozaantigua/35950343474/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22134, 'Callejâ”œâ”‚n de Rodâ”œâ”‚n 1951', 'Imagen capturada desde el arbolado paseo de las Damas (antiguo de Sasera) y centrada en el principio del desaparecido callejâ”œâ”‚n de Rodâ”œâ”‚n (actual calle de San Ignacio de Loyola), asâ”œآ، denominado por la presencia de la importante fundiciâ”œâ”‚n de Rodâ”œâ”‚n (a la izquierda). Este sinuoso camino serpenteaba entre torres y huertos de las Adulas (a la derecha), el colegio del Salvador, diversos talleres y almacenes industriales, hasta desembocar cerca del camino de los Plâ”œأ­tanos. Fuente visual: Juan Mora Insa, AMZ.', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.64590100, -0.88470900, '0101000020E61000007842AF3F894FECBF13BA4BE2ACD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23972165597.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23972165597.webp', 'https://www.flickr.com/photos/zaragozaantigua/23972165597/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
